using System.Text;

namespace ShaRPC.SourceGenerator;

/// <summary>
/// Generates client proxy classes for ShaRPC services. The generated proxy implements
/// the user's interface exactly — same return types, same parameter list, only adding
/// a forwarding body to <see cref="ShaRPC.Core.Client.IShaRpcClient"/>. All emitted
/// type references are fully qualified with <c>global::</c> so the generated file
/// never depends on the user's <c>using</c> set.
/// </summary>
internal static class ProxyGenerator
{
    public static string Generate(ServiceModel service)
    {
        var sb = new StringBuilder();
        var proxyName = NamingHelpers.StripInterfacePrefix(service.InterfaceName) + "Proxy";
        var qualifiedInterface = QualifyServiceType(service, service.InterfaceName);

        sb.AppendLine("// <auto-generated />");
        sb.AppendLine("#nullable enable");
        sb.AppendLine();

        if (!string.IsNullOrEmpty(service.Namespace))
        {
            sb.AppendLine($"namespace {service.Namespace}");
            sb.AppendLine("{");
        }

        sb.AppendLine("    /// <summary>");
        sb.AppendLine($"    /// Client proxy for {service.InterfaceName}.");
        sb.AppendLine("    /// </summary>");
        sb.AppendLine($"    public sealed class {proxyName} : {qualifiedInterface}");
        sb.AppendLine("    {");
        sb.AppendLine("        private readonly global::ShaRPC.Core.Client.IShaRpcClient _client;");
        sb.AppendLine();
        sb.AppendLine($"        public {proxyName}(global::ShaRPC.Core.Client.IShaRpcClient client)");
        sb.AppendLine("        {");
        sb.AppendLine("            _client = client ?? throw new global::System.ArgumentNullException(nameof(client));");
        sb.AppendLine("        }");

        foreach (var method in service.Methods.Array)
        {
            sb.AppendLine();
            GenerateProxyMethod(sb, service, method);
        }

        sb.AppendLine("    }");

        if (!string.IsNullOrEmpty(service.Namespace))
        {
            sb.AppendLine("}");
        }

        return sb.ToString();
    }

    /// <summary>Builds a <c>global::Namespace.InterfaceName</c> reference.</summary>
    private static string QualifyServiceType(ServiceModel service, string typeName) =>
        string.IsNullOrEmpty(service.Namespace)
            ? "global::" + typeName
            : $"global::{service.Namespace}.{typeName}";

    private static void GenerateProxyMethod(StringBuilder sb, ServiceModel service, MethodModel method)
    {
        var paramList = new StringBuilder();
        for (var i = 0; i < method.Parameters.Count; i++)
        {
            if (i > 0) paramList.Append(", ");
            var p = method.Parameters[i];
            paramList.Append(p.RefKindKeyword).Append(p.Type).Append(' ').Append(p.Name);
        }
        if (method.HasCancellationToken)
        {
            if (paramList.Length > 0) paramList.Append(", ");
            paramList.Append("global::System.Threading.CancellationToken ct = default");
        }

        var declaredReturn = NamingHelpers.GetDeclaredReturnTypeText(method.ReturnKind, method.UnwrappedReturnType);
        var isAsync = NamingHelpers.IsAsync(method.ReturnKind);
        // Methods whose shape we cannot marshal (ref/in/out parameters) are emitted as a
        // throwing stub so the proxy class still implements the user's interface. We do
        // NOT add `async` for stubs — the throw must take the synchronous exit path so
        // out-parameters are considered definitely assigned by the C# compiler.
        var asyncKeyword = (isAsync && method.UnsupportedReason is null) ? "async " : string.Empty;
        var ctArg = method.HasCancellationToken ? "ct" : "default";

        sb.AppendLine($"        public {asyncKeyword}{declaredReturn} {method.Name}({paramList})");
        sb.AppendLine("        {");

        if (method.UnsupportedReason is not null)
        {
            sb.AppendLine($"            throw new global::System.NotSupportedException(\"ShaRPC cannot marshal '{method.Name}': {ShaRpcGenerator.EscapeStringLiteral(method.UnsupportedReason)}\");");
        }
        else
        {
            var invocation = BuildClientInvocation(service, method, ctArg);
            EmitInvocation(sb, method, invocation);
        }

        sb.AppendLine("        }");
    }

    /// <summary>
    /// Builds the call to <c>_client.InvokeAsync(...)</c>. Picks the most direct overload
    /// available on <see cref="ShaRPC.Core.Client.IShaRpcClient"/> for the (parameter-count,
    /// has-return-payload) shape of the user's method.
    /// </summary>
    private static string BuildClientInvocation(ServiceModel service, MethodModel method, string ctArg)
    {
        var hasReturn = NamingHelpers.HasReturnValue(method.ReturnKind);
        var returnType = method.UnwrappedReturnType;
        var svc = service.ServiceName;
        var rpc = method.RpcName;

        if (method.Parameters.Count == 0)
        {
            if (hasReturn)
            {
                // Task<TResponse> InvokeAsync<TResponse>(svc, method, ct)
                return $"_client.InvokeAsync<{returnType}>(\"{svc}\", \"{rpc}\", {ctArg})";
            }

            // Void / Task / ValueTask without response. We use the no-response overload
            // (Task InvokeAsync<TRequest>) and pass a small dummy payload, because the
            // no-request overload (#2) returns Task<TResponse> which would force the
            // serializer to deserialize a response that the dispatcher never wrote.
            return $"_client.InvokeAsync<object>(\"{svc}\", \"{rpc}\", new object(), {ctArg})";
        }

        if (method.Parameters.Count == 1)
        {
            var p = method.Parameters[0];
            if (hasReturn)
            {
                return $"_client.InvokeAsync<{p.Type}, {returnType}>(\"{svc}\", \"{rpc}\", {p.Name}, {ctArg})";
            }
            return $"_client.InvokeAsync<{p.Type}>(\"{svc}\", \"{rpc}\", {p.Name}, {ctArg})";
        }

        // Multiple parameters — pack into a ValueTuple payload.
        var tupleTypes = new StringBuilder();
        var tupleValues = new StringBuilder();
        for (var i = 0; i < method.Parameters.Count; i++)
        {
            if (i > 0)
            {
                tupleTypes.Append(", ");
                tupleValues.Append(", ");
            }
            tupleTypes.Append(method.Parameters[i].Type);
            tupleValues.Append(method.Parameters[i].Name);
        }

        if (hasReturn)
        {
            return $"_client.InvokeAsync<({tupleTypes}), {returnType}>(\"{svc}\", \"{rpc}\", ({tupleValues}), {ctArg})";
        }
        return $"_client.InvokeAsync<({tupleTypes})>(\"{svc}\", \"{rpc}\", ({tupleValues}), {ctArg})";
    }

    private static void EmitInvocation(StringBuilder sb, MethodModel method, string invocation)
    {
        switch (method.ReturnKind)
        {
            case MethodReturnKind.Void:
                sb.AppendLine($"            {invocation}.GetAwaiter().GetResult();");
                break;

            case MethodReturnKind.Sync:
                sb.AppendLine($"            return {invocation}.GetAwaiter().GetResult();");
                break;

            case MethodReturnKind.Task:
            case MethodReturnKind.ValueTask:
                sb.AppendLine($"            await {invocation};");
                break;

            case MethodReturnKind.TaskOf:
            case MethodReturnKind.ValueTaskOf:
                sb.AppendLine($"            return await {invocation};");
                break;
        }
    }
}
